return ['domain'=>NULL,'plural-forms'=>'nplurals=3; plural=(n%10==1 && n%100!=11 ? 0 : n%10>=2 && n%10<=4 && (n%100<10 || n%100>=20) ? 1 : 2);','language'=>'hr','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-03-27 09:00:36+0000','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Ažurirajte dodatak TranslatePress - Multilingual na verziju %1$s ili noviju kako biste osigurali ispravan rad %2$s.','Please install and activate the TranslatePress - Multilingual plugin'=>'Instalirajte i aktivirajte TranslatePress - višejezični dodatak','Install & Activate'=>'Instaliraj i aktiviraj','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Ažurirajte TranslatePress - Multilingual na verziju %2$s ili noviju. Trenutno instalirana verzija dodatka TranslatePress - Multilingual više nije kompatibilna s trenutnom verzijom %1$s.','All TranslatePress functionalities are disabled until then.'=>'Sve funkcionalnosti TranslatePressa su do tada onemogućene.','Update Now'=>'Ažuriraj','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Ovaj dodatak za TranslatePress premješten je u glavni dodatak i više se ne koristi. Možete ga izbrisati.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> zahtijeva najmanje PHP verziju 5.6.20+ za rad. To je <a href="%s">minimalni zahtjev za najnoviju verziju WordPressa</a>. Obratite se svom administratoru poslužitelja da ažurira svoju verziju PHP-a.','Advanced'=>'Napredno','Settings saved.'=>'Postavke su spremljene.','Are you sure you want to remove this item?'=>'Jeste li sigurni da želite ukloniti ovu stavku?','Remove'=>'Ukloni','Add'=>'Dodaj','Select...'=>'Odaberi...','[%s] Low TranslatePress AI Words'=>'[%s] Niska razina TranslatePress AI riječi','upgrade your plan or get extra AI Words'=>'nadogradite svoj plan ili nabavite dodatne AI riječi','upgrade your plan'=>'nadogradite svoj plan','TranslatePress AI words are running low on your site.'=>'TranslatePress AI riječi su na izmaku na vašoj web stranici.','Current status: %s words remaining'=>'Trenutni status: preostalo %s riječi','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Kad preostale AI riječi ponestanu, automatski prijevod putem TranslatePress AI-a bit će pauziran.','To continue translating your content, please %1$s over at %2$s'=>'Da biste nastavili prevoditi svoj sadržaj, molimo vas da %1$s na %2$s.','Manage Notification: %s'=>'Upravljanje obavijestima: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Dostupna je nova verzija %1$s. %2$sPogledajte detalje%4$s verzije %3$s ili %5$sažurirajte sada%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Dostupna je nova verzija %1$s. %2$sPogledajte verziju %3$s detalji%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Da biste omogućili ažuriranja, %1$sunesite svoj licenčni ključ%2$s. Trebate licenčni ključ? %3$sKupite ga sada%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Da biste omogućili ažuriranja, idite na stranicu %1$slicenca%2$s i provjerite imate li valjanu licencu.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Da biste omogućili ažuriranja, potrebno je obnoviti licencu. Idite na stranicu %1$sTranslatePress račun%2$s i prijavite se za obnovu.','You do not have permission to install plugin updates'=>'Nemate dopuštenje za instaliranje ažuriranja dodataka','Error'=>'Greška','Your TranslatePress license key is invalid or missing.'=>'Vaš TranslatePress licenčni ključ nije valjan ili nedostaje.','Your license key expired on %s.'=>'Vaš licencni ključ istekao je %s.','Your license key has been disabled.'=>'Vaš licencni ključ je onemogućen.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Vaš licenčni ključ je onemogućen za ovaj URL. Ponovno ga omogućite iz <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Upravljanje stranicama.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Neusklađenost licenčnog ključa.</strong> Licenca koju ste unijeli ne odgovara verziji TranslatePress koju ste instalirali.</p><p>Provjerite jeste li instalirali ispravnu verziju za svoju licencu sa svog TranslatePress računa.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Ako imate instaliran samo besplatni dodatak, ali ste dodali plaćenu licencu, molimo instalirajte plaćeni dodatak sa svog TranslatePress računa.','Your license key has reached its activation limit.'=>'Vaš licencni ključ dosegao je ograničenje aktivacije.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Nadogradite svoju tarifu da biste dodali više web stranica. %1$sNadogradite sada%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Ova web stranica je već aktivirana pod besplatnom licencom. Svaka web stranica može koristiti samo jednu besplatnu licencu.','An error occurred, please try again.'=>'Došlo je do greške, pokušajte ponovno.','You have successfully activated your license'=>'Uspješno ste aktivirali svoju licencu','Others'=>'Ostali','Restrict by Language'=>'Ograniči prema jeziku','Exclude from Language'=>'Isključi iz jezika','Restrict element to language'=>'Ograničite element na jezik','Show this element only in one language.'=>'Prikažite ovaj element samo na jednom jeziku.','Enable translation'=>'Omogući prijevod','Allow translation to the corresponding language only if the content is written in the default language.'=>'Dopusti prijevod na odgovarajući jezik samo ako je sadržaj napisan na zadanom jeziku.','Select language'=>'Odaberite jezik','Choose in which language to show this element.'=>'Odaberite na kojem jeziku želite prikazati ovaj element.','Exclude element from language'=>'Izuzimanje elementa iz jezika','Exclude this element from specific languages.'=>'Izuzmite ovaj element iz određenih jezika.','Select languages'=>'Odaberite jezike','Choose from which languages to exclude this element.'=>'Odaberite iz kojih jezika želite izuzeti ovaj element.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Ovaj će element i dalje biti vidljiv kada prevodite svoju web stranicu putem uređivača prijevoda.','The content of this element should be written in the default language.'=>'Sadržaj ovog elementa trebao bi biti napisan na zadanom jeziku.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> je naišao na SQL pogreške. <a href="%s" title="View TranslatePress SQL Errors">Provjerite pogreške</a>.','Automatic translation has been disabled.'=>'Automatski prijevod je onemogućen.','Dismiss this notice.'=>'Odbaci ovu obavijest.','Logged errors'=>'Zabilježene greške','These are the most recent 5 errors logged by TranslatePress:'=>'Ovo je najnovijih 5 pogrešaka koje je zabilježio TranslatePress:','Yes'=>'Da','Why are these errors occuring'=>'Zašto se pojavljuju ove pogreške','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Ako TranslatePress otkrije nešto pogrešno prilikom izvršavanja upita u vašoj bazi podataka, može onemogućiti značajku automatskog prijevoda kako bi izbjegao dodatno naplaćivanje od strane Googlea/DeepL-a. Automatski prijevod potrebno je ručno uključiti nakon što riješite probleme.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Otkrivene SQL pogreške mogu se pojaviti iz različitih razloga, uključujući tablice koje nedostaju, nedostajuće dozvole za SQL korisnika za stvaranje tablica ili izvođenje drugih operacija, probleme nakon migracije web-mjesta ili promjene konfiguracije SQL servera.','What you can do in this situation'=>'Što možete učiniti u ovoj situaciji','Plan A.'=>'Plan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Idite na Postavke -> TranslatePress -> karticu Općenito i Spremi postavke. Ovo će ponovno generirati tablice pomoću vaših trenutnih SQL postavki. Provjerite pojavljuju li se više pogreške tijekom pregledavanja vaše web stranice na prevedenom jeziku. Pogledajte vremenske oznake pogrešaka kako biste bili sigurni da ne vidite stare pogreške. Prikazuje se samo zadnjih 5 grešaka.','Plan B.'=>'Plan B.','If your problem isn\'t solved, try the following steps:'=>'Ako problem nije riješen, pokušajte sljedeće korake:','Create a backup of your database'=>'Stvorite sigurnosne kopije baze podataka','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Napravite kopiju svake tablice prijevoda u kojoj naiđete na greške. Možete kopirati tablicu unutar iste baze podataka (trp_dictionary_en_us_es_es_COPY na primjer) -- izvršite ovaj korak samo ako želite zadržati trenutne prijevode','Remove the trouble tables by executing the DROP function on them'=>'Uklonite tablice problema izvršavanjem funkcije DROP na njima','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Idite na Postavke -> TranslatePress -> karticu Općenito i Spremi postavke. Ovo će ponovno generirati tablice pomoću vašeg trenutnog SQL poslužitelja.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Kopirajte relevantni sadržaj iz dupliciranih tablica (trp_dictionary_en_us_es_es_COPY na primjer) u novogeneriranu tablicu (trp_dictionary_en_us_es_es) -- izvršite ovaj korak samo ako želite zadržati trenutne prijevode','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Testirajte ga da vidite radi li sve. Ako je nešto pošlo krivo, možete vratiti sigurnosnu kopiju koju ste napravili u prvom koraku. Provjerite pojavljuju li se više pogreške tijekom pregledavanja vaše web stranice na prevedenom jeziku. Pogledajte vremenske oznake pogrešaka kako biste bili sigurni da ne vidite stare pogreške. Prikazuje se samo zadnjih 5 grešaka.','Plan C.'=>'Plan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Ako vaš problem još uvijek nije riješen, pokušajte pitati svog hostinga o svojim pogreškama. Najčešći problem je nedostatak dopuštenja za SQL korisnika, kao što je dopuštenje za stvaranje tablica.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Nije moguće instalirati. Pokušajte ponovno s <a href="%s" >nadzorne ploče dodataka.</a>','Active'=>'Aktivan','Permission denied.'=>'Dozvola je odbijena.','Invalid nonce.'=>'Nevažeći nonce.','Settings scope unknown.'=>'Opseg postavki nepoznat.','Legacy disabled.'=>'Naslijeđeno je onemogućeno.','Language Switcher'=>'Izmjenjivač jezika','Change language to %s'=>'Promijenite jezik u %s','Automatic Translation'=>'Automatski prijevod','DeepL'=>'DeepL','Unsupported languages'=>'Nepodržani jezici','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Odabrani mehanizam za automatsko prevođenje ne pruža podršku za ove jezike.<br>I dalje možete ručno prevoditi stranice na ovim jezicima pomoću Uređivača prijevoda.','API key validation failed.'=>'Provjera valjanosti API ključa nije uspjela.','API key verification was successful.'=>'Provjera API ključa bila je uspješna.','Please enter your Google Translate key.'=>'Molim, unesite svoj Google Translate ključ.','Please enter your DeepL API key.'=>'Unesite svoj DeepL API ključ.','Not TranslatePress onboarding page.'=>'Nije stranica za uključivanje TranslatePressa.','Step %s does not exist'=>'Korak %s ne postoji','Welcome'=>'Dobro došli','Add Languages'=>'Dodaj jezike','Enable Addons'=>'Omogući dodatke','Finalize'=>'Završi','Exit Setup'=>'Napusti postavljanje','Upgrade'=>'Nadogradnja','Nothing here'=>'Ovdje nema ništa','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Vaša licenca <strong>za TranslatePress</strong> nedostaje ili je nevažeća. <br/>Registrirajte %1$ssvoj primjerak%2$s kako biste omogućili automatski prijevod web stranice putem TranslatePress AI, premium dodataka, automatskih ažuriranja i podrške. Trebate licenčni ključ? %3$sKupite ga odmah%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Vaša licenca <strong>za TranslatePress</strong> istječe dana %1$s. Obnovite %2$ssvoju licencu%3$s kako biste nastavili primati pristup automatskim prijevodima putem TP AI, premium dodacima, preuzimanjima proizvoda i automatskim ažuriranjima. %4$sObnovi odmah%5$s','Error: '=>'Greška: ','Something went wrong, please try again.'=>'Nešto je pošlo po zlu, pokušajte ponovno.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Vaša licenca <strong>za TranslatePress</strong> je istekla. <br/>Obnovite %1$ssvoju licencu%2$s kako biste nastavili primati pristup automatskim prijevodima putem TranslatePress AI, premium dodataka, preuzimanja proizvoda i automatskih ažuriranja. %3$sObnovi odmah %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Neusklađenost licenčnog ključa. Licenca koju ste unijeli ne odgovara verziji koju <strong>%1$s</strong> ste instalirali. <br/>Provjerite jeste li instalirali ispravnu verziju za svoju licencu sa svog %2$sTranslatePress računa%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Ako imate instaliran samo besplatni dodatak, ali ste dodali plaćenu licencu, molimo instalirajte plaćeni dodatak sa svog TranslatePress računa.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Dosegli ste ograničenje aktivacije za svoju <strong>%1$s</strong> licencu. <br/>Upravljajte svojim aktivnim web stranicama sa %2$s svog računa %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Vaša je licenca onemogućena za ovaj URL. Ponovno ga omogućite iz <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Upravljanje stranicama.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'%1$s automatsko prevođenje zahtijeva aktivnu licencu. Molimo %2$sobnovite%3$s svoju licencu ili kupite novu %4$sovdje%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Molimo %1$sunesite%2$s svoj licenčni ključ kako biste omogućili %3$s automatski prijevod.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Ostalo vam je manje od 5,000 TranslatePress AI riječi. Da biste nastavili s automatskim prevođenjem svoje web stranice, %skupite dodatne AI riječi s popustom sa svog računa%s.',' Error: '=>' Greška: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Ova web stranica je već aktivirana pod besplatnom licencom. Svaka web stranica može koristiti samo jednu besplatnu licencu. Nadogradite na premium plan za više riječi TranslatePress AI s %1$s svog računa %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Nemate važeću licencu za <strong>TranslatePress</strong>. %1$sNabavite jednu besplatno%2$s da biste dobili pristup TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NOVO:</strong> Stigao je dodatak <strong>Different Domain per Language</strong>! Poboljšajte svoj globalni SEO i stvorite lokalno iskustvo s domenama specifičnim za zemlju poput .de ili .fr. Nadogradite na <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business ili Developer</a> kako biste mu pristupili + još više premium pogodnosti!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NOVO:</strong> Stigao je dodatak <strong>Different Domain per Language</strong>! Poboljšajte svoj globalni SEO i stvorite lokalno iskustvo s domenama specifičnim za zemlju poput .de ili .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Saznajte više</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Prekoračena je dnevna kvota za znakove strojnog prevođenja. Za više informacija provjerite <strong>stranicu TranslatePress -> <a href="%s">Automatski prijevod</a></strong>.','Marketing optin'=>'Uključivanje u marketing','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Uključite se u naše obavijesti o sigurnosnim ažuriranjima i ažuriranjima značajki te neosjetljivom dijagnostičkom praćenju.','TranslatePress Preferred User Language'=>'TranslatePress Preferirani korisnički jezik','Preferred language to navigate the site'=>'Preferirani jezik za navigaciju stranicom','The language is automatically set based by the last visited language by the user.'=>'Jezik se automatski postavlja na temelju posljednjeg jezika koji je korisnik posjetio.','Always use this language'=>'Uvijek koristite ovaj jezik','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Provjerom ove postavke preferirani jezik ostat će gore odabrani, bez mogućnosti promjene u sučelju. <br>Ovaj jezik će se koristiti u različitim operacijama kao što je slanje e-pošte korisniku.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Pozdrav! Čini se da već neko vrijeme koristite <strong>TranslatePress</strong> za prevođenje svoje web stranice. To je sjajno! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Ako možete odvojiti nekoliko trenutaka da ga ocijenite na WordPress.org to bi nam puno pomoglo (i povećalo moju motivaciju).','~ Razvan, developer of TranslatePress'=>'~ Razvan, programer TranslatePressa','Rate TranslatePress on WordPress.org plugin page'=>'Ocijeni TranslatePress na WordPress.org stranici dodatka','Ok, I will gladly help!'=>'U redu, rado ću pomoći!','No, thanks.'=>'Ne, hvala.','Full Language Names'=>'Puni nazivi jezika','Short Language Names'=>'Kratki nazivi jezika','Flags with Full Language Names'=>'Zastave s punim nazivima jezika','Flags with Short Language Names'=>'Zastave s kratkim jezičnim nazivima','Only Flags'=>'Samo zastave','Full Language Names No HTML'=>'Puni nazivi jezika bez HTML-a','Bottom Right'=>'Dolje desno','Bottom Left'=>'Dolje lijevo','Top Right'=>'Gore desno','Top Left'=>'Gore lijevo','Dark'=>'Tamno','Light'=>'Svijetlo','Deactivate'=>'Deaktiviraj','Activate'=>'Aktiviraj','Invalid language code. Please try again.'=>'Nevažeći kod jezika. Pokušajte ponovno.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Kodovi jezika mogu sadržavati samo A-Z a-z 0-9 - _ znakova. Provjerite kodove jezika u TranslatePress Opće postavke.','Error! Duplicate URL slug values.'=>'Greška! Duplicirane vrijednosti URL-a.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Ne možete odabrati dva jezika koji imaju isti <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso kod</a>, ali različite formalnosti jer će to dovesti do duplikata <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang oznake</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Otkriven je dvostruki jezik.<br>Svaki jezik može se dodati samo jednom kako bi se osiguralo točno upravljanje prijevodom.<br> Promijenite unos duplikata jezika i pokušajte ponovno. ','Current Language'=>'Trenutačni jezik','Opposite Language'=>'Suprotni jezik','General'=>'Općenito','Translate Site'=>'Prevedi stranicu','Addons'=>'Dodaci','License'=>'Licenca','Settings'=>'Postavke','Activate License'=>'Aktiviraj licencu','Pro Features'=>'Pro značajke','Need Help?'=>'Trebate pomoć?','Recent community discussions'=>'Nedavne rasprave u zajednici','Loading...'=>'Učitavanje ...','Unable to load forum posts'=>'Nije moguće učitati forumske objave','Ask a Question'=>'Postavite pitanje','View All Topics'=>'Pogledajte sve teme','by'=>'od','Have a question?'=>'Imate pitanje?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Zatražite pomoć izravno od developera plugina, predložite poboljšanja ili podijelite 